# price cache
# Fix: expired cache entries should refresh, keyed by (SKU, currency).
import time


class PriceCache:
    def __init__(self, fetcher, ttl=60, now=time.monotonic):
        self._fetcher = fetcher
        self._ttl = ttl
        self._now = now
        self._entries = {}  # (sku, currency) -> (price, expires_at)

    def get(self, sku, currency):
        key = (sku, currency)
        now = self._now()
        entry = self._entries.get(key)
        if entry is not None:
            price, expires_at = entry
            if now < expires_at:
                return price
        price = self._fetcher(sku, currency)
        self._entries[key] = (price, now + self._ttl)
        return price

    def invalidate(self, sku=None, currency=None):
        if sku is None and currency is None:
            self._entries.clear()
            return
        for key in list(self._entries):
            k_sku, k_cur = key
            if (sku is None or k_sku == sku) and (currency is None or k_cur == currency):
                del self._entries[key]

